const item = $input.first().json;
const existingSelection = String(item['Existing Employee'] || '').trim();
const firstNameTyped = String(item['First Name'] || '').trim();
const lastNameTyped = String(item['Last Name'] || '').trim();

let sAMAccountName = '', firstName = '', lastName = '', pickedExisting = false;

if (existingSelection) {
  const m = existingSelection.match(/\(([^)]+)\)\s*$/);
  if (!m) throw new Error(`Could not parse username from Existing Employee selection: ${existingSelection}`);
  sAMAccountName = m[1].trim();
  const namePart = existingSelection.slice(0, m.index).trim();
  const spaceIdx = namePart.indexOf(' ');
  firstName = spaceIdx !== -1 ? namePart.substring(0, spaceIdx).trim() : namePart;
  lastName = spaceIdx !== -1 ? namePart.substring(spaceIdx + 1).trim() : '';
  pickedExisting = true;
} else if (firstNameTyped && lastNameTyped) {
  firstName = firstNameTyped;
  lastName = lastNameTyped;
  sAMAccountName = (firstName.charAt(0) + lastName).toLowerCase();
} else {
  throw new Error('Select an existing employee, or enter both First Name and Last Name.');
}

const homeFolderRaw = item['Home Folder (Z: Drive)'];
const homeFolderChecked = Array.isArray(homeFolderRaw) ? homeFolderRaw.length > 0 : !!homeFolderRaw;

return [{ json: {
  ...item,
  sAMAccountName, firstName, lastName, pickedExisting, homeFolderChecked
} }];

const resolved = $('Resolve identity').first().json;
const searchResults = $input.all();
const firstJson = searchResults.length > 0 ? searchResults[0].json : {};
const userExists = searchResults.length > 0 && !!firstJson.dn;

let existingDn = null, userAccountControl = null, isEnabled = false, existing = {};
if (userExists) {
  existingDn = firstJson.dn || firstJson.distinguishedName || null;
  userAccountControl = parseInt(firstJson.userAccountControl ?? '514', 10);
  isEnabled = (userAccountControl & 2) === 0;
  existing = {
    cn: firstJson.cn, title: firstJson.title, company: firstJson.company,
    streetAddress: firstJson.streetAddress, l: firstJson.l, st: firstJson.st,
    postalCode: firstJson.postalCode, telephoneNumber: firstJson.telephoneNumber,
    mail: firstJson.mail
  };
}

return [{ json: {
  ...resolved, userExists, existingDn, isEnabled, existing
} }];

const result = $input.first().json;

function backLink() {
  return `<p style="margin-top:16px;"><a href="http://localhost:5678/form/65a75b55-2033-44a1-8c78-e2f891409f34" style="color:#3182ce; font-size:13px;">← Back to form</a></p>`;
}

function errorPage(message) {
  return `<div style="font-family: 'Open Sans', sans-serif; max-width: 480px; margin: 40px auto; padding: 32px; background: #fff; border-radius: 8px; box-shadow: 0 4px 16px rgba(99,77,255,0.08); border-top: 4px solid #c53030;">
  <div style="display:flex; align-items:center; margin-bottom:16px;">
    <span style="font-size:28px; margin-right:12px;">⚠️</span>
    <h2 style="margin:0; color:#c53030; font-size:20px;">Missing or Invalid Information</h2>
  </div>
  <p style="color:#555; font-size:14px; line-height:1.6; margin:0;">${message}</p>
  ${backLink()}
</div>`;
}

if (result.success === undefined) {
  const message = String(result.error?.message || result.error || 'Something went wrong processing your submission.').replace(/\s*\[line \d+\]\s*$/, '');
  return [{ json: { responseHtml: errorPage(message) } }];
}

let route = {};
try { route = $('Code: Route - exists or new').first().json; } catch (e) {}

const isCreate = !route.userExists;
const isReenable = !!result.reenabled;

let heading, message, color, icon;
if (!result.success) {
  heading = 'Provisioning Error';
  color = '#c53030';
  icon = '⚠️';
  message = `Something went wrong: ${(result.errors || []).join('; ') || 'Unknown error'}`;
} else if (isCreate) {
  heading = 'User Created Successfully';
  color = '#276749';
  icon = '✅';
  message = `The Active Directory account <strong>${result.sAMAccountName}</strong> has been created. The user can log in with their temporary password and will be prompted to change it on first sign-in.`;
} else if (isReenable) {
  heading = 'User Re-enabled Successfully';
  color = '#2b6cb0';
  icon = '🔄';
  message = `The Active Directory account <strong>${result.sAMAccountName}</strong> has been updated and re-enabled. The user can log in with their temporary password and will be prompted to change it on first sign-in.`;
} else {
  heading = 'User Updated Successfully';
  color = '#2b6cb0';
  icon = '✅';
  message = `The Active Directory account <strong>${result.sAMAccountName}</strong> has been updated.`;
}

const warningsHtml = (result.success && result.errors && result.errors.length > 0)
  ? `<p style="color:#c05621; font-size:13px; margin-top:12px;">Note: ${result.errors.join('; ')}</p>`
  : '';

const responseHtml = `<div style="font-family: 'Open Sans', sans-serif; max-width: 480px; margin: 40px auto; padding: 32px; background: #fff; border-radius: 8px; box-shadow: 0 4px 16px rgba(99,77,255,0.08); border-top: 4px solid ${color};">
  <div style="display:flex; align-items:center; margin-bottom:16px;">
    <span style="font-size:28px; margin-right:12px;">${icon}</span>
    <h2 style="margin:0; color:${color}; font-size:20px;">${heading}</h2>
  </div>
  <p style="color:#555; font-size:14px; line-height:1.6; margin:0;">${message}</p>
  ${warningsHtml}
</div>`;

return [{ json: { responseHtml } }];

